SELECT * FROM ( SELECT p.POST_ID AS postId, p.FK_MEMBERID AS memberId, p.FK_BOARD_ID AS boardId, p.TITLE AS title, p.POST_STATUS AS postStatus, p.VIEW_COUNT AS viewCount, p.CREATED_AT AS createdAt, p.UPDATED_AT AS updatedAt, p.IS_HIDDEN AS isHidden, ROW_NUMBER() OVER (ORDER BY p.CREATED_AT DESC) AS rn FROM TBL_POST p
AND p.POST_STATUS != 'DELETED'
AND p.IS_HIDDEN = #{isHidden}
AND (p.TITLE LIKE '%' || #{search} || '%' OR p.FK_MEMBERID LIKE '%' || #{search} || '%')
) WHERE rn BETWEEN #{offset}+1 AND #{offset}+#{limit}

SELECT COUNT(*) FROM TBL_POST
WHERE IS_HIDDEN = #{isHidden}
AND POST_STATUS != 'DELETED'

SELECT * FROM ( SELECT c.COMMENT_ID AS commentId, c.FK_POST_ID AS postId, c.FK_MEMBERID AS memberId, c.CONTENT AS content, c.FK_PARENT_COMMENT_ID AS parentCommentId, c.STATUS AS status, c.CREATED_AT AS createdAt, c.UPDATED_AT AS updatedAt, c.IS_HIDDEN AS isHidden, ROW_NUMBER() OVER (ORDER BY c.CREATED_AT DESC) AS rn FROM TBL_COMMENT c
AND c.STATUS != 'DELETED'
AND c.IS_HIDDEN = #{isHidden}
AND (c.CONTENT LIKE '%' || #{search} || '%' OR c.FK_MEMBERID LIKE '%' || #{search} || '%')
) WHERE rn BETWEEN #{offset}+1 AND #{offset}+#{limit}

SELECT COUNT(*) FROM TBL_COMMENT
WHERE IS_HIDDEN = #{isHidden}
AND STATUS != 'DELETED'

